import sys
stack = []
class Solution:
    def push(self, element):
        stack.append(element)
        return True

    def pop(self):
        if not self.stack:
            return False
        self.stack.pop()
        return True

    def topmostElement(self):
        if not self.stack:
            raise Exception('Empty stack')
        return self.stack[-1]
s = Solution()
input_count = int(sys.stdin.readline())
for _ in range(input_count):
    sys.stdin.readline()
elements = sys.stdin.readline().strip().split()
for element in elements:
    s.push(int(element))
for _ in range(5):
    s.pop()
    topmost = s.topmostElement()
    print(topmost)

